"use client";

import { useState, useEffect, useCallback } from "react";
import { WaitKit } from "./index";
import type { JoinOptions, JoinResult } from "./types";

export interface UseWaitlistReturn {
  join: (data: JoinOptions) => Promise<JoinResult>;
  count: number | null;
  isJoining: boolean;
  isLoading: boolean;
  error: Error | null;
  refetchCount: () => Promise<void>;
}

export function useWaitlist(wk: WaitKit): UseWaitlistReturn {
  const [count, setCount] = useState<number | null>(null);
  const [isLoading, setIsLoading] = useState(true);
  const [isJoining, setIsJoining] = useState(false);
  const [error, setError] = useState<Error | null>(null);

  const fetchCount = useCallback(async () => {
    try {
      setIsLoading(true);
      setError(null);
      const result = await wk.subscribers.count();
      setCount(result);
    } catch (err) {
      setError(err instanceof Error ? err : new Error("Failed to fetch count"));
    } finally {
      setIsLoading(false);
    }
  }, [wk]);

  useEffect(() => {
    fetchCount();
  }, [fetchCount]);

  const join = useCallback(
    async (data: JoinOptions): Promise<JoinResult> => {
      setIsJoining(true);
      setError(null);
      try {
        const result = await wk.subscribers.create(data);
        await fetchCount();
        return result;
      } catch (err) {
        const error =
          err instanceof Error ? err : new Error("Failed to join waitlist");
        setError(error);
        throw error;
      } finally {
        setIsJoining(false);
      }
    },
    [wk, fetchCount],
  );

  return {
    join,
    count,
    isJoining,
    isLoading,
    error,
    refetchCount: fetchCount,
  };
}
